{"name": "stock", "description": "Fetch and analyze stock data for Chinese A-share companies (e.g. 杭汽轮, 阿里巴巴) using public financial APIs.", "code": "import requests

def get_stock_data(symbol):
    url = f"https://query2.finance.yahoo.com/v8/finance/chart/{symbol}.SS"
    headers = {"User-Agent": "Mozilla/5.0"}
    response = requests.get(url, headers=headers)
    if response.status_code != 200:
        return None
    data = response.json()
    return {
        'price': data['chart']['result'][0]['meta']['regularMarketPrice'],
        'change': data['chart']['result'][0]['meta']['regularMarketChange'],
        'volume': data['chart']['result'][0]['meta']['regularMarketVolume']
    }

